import React, { useState, useEffect } from 'react';
import './App.css';

const API_BASE = 'http://localhost/Weather-Alert';

// Grenada parishes data
const PARISHES = [
  { id: 'saint-george', name: "Saint George", capital: "St. George's", lat: 12.0561, lon: -61.7486 },
  { id: 'saint-andrew', name: "Saint Andrew", capital: "Grenville", lat: 12.1167, lon: -61.6167 },
  { id: 'saint-david', name: "Saint David", capital: "St. David's", lat: 12.0333, lon: -61.7000 },
  { id: 'saint-john', name: "Saint John", capital: "Gouyave", lat: 12.1667, lon: -61.7333 },
  { id: 'saint-mark', name: "Saint Mark", capital: "Victoria", lat: 12.1833, lon: -61.7000 },
  { id: 'saint-patrick', name: "Saint Patrick", capital: "Sauteurs", lat: 12.2167, lon: -61.6333 },
  { id: 'carriacou', name: "Carriacou", capital: "Hillsborough", lat: 12.4789, lon: -61.4492 }
];

function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState('login');
  const [currentTab, setCurrentTab] = useState('dashboard');

  // Form states
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [error, setError] = useState('');
  const [formLoading, setFormLoading] = useState(false);

  // Weather state
  const [weather, setWeather] = useState(null);
  const [parish, setParish] = useState(PARISHES[0]);
  const [weatherLoading, setWeatherLoading] = useState(false);
  const [isDark, setIsDark] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem('auth_token');
    const storedUser = localStorage.getItem('user');

    if (token && storedUser) {
      setUser(JSON.parse(storedUser));
      setPage('dashboard');
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    if (user && page === 'dashboard') {
      fetchWeather();
    }
  }, [user, parish]);

  const fetchWeather = async () => {
    setWeatherLoading(true);
    try {
      const params = new URLSearchParams({
        latitude: parish.lat,
        longitude: parish.lon,
        current: 'temperature_2m,relative_humidity_2m,precipitation,rain,cloud_cover,wind_speed_10m',
        hourly: 'temperature_2m,precipitation_probability,precipitation,cloud_cover',
        daily: 'temperature_2m_max,temperature_2m_min,precipitation_sum',
        temperature_unit: 'celsius',
        timezone: 'auto',
        forecast_days: 7
      });

      const response = await fetch(`https://api.open-meteo.com/v1/forecast?${params}`);
      const data = await response.json();

      setWeather({
        current: {
          temperature: Math.round(data.current.temperature_2m),
          humidity: Math.round(data.current.relative_humidity_2m),
          rain: data.current.rain || 0,
          cloud_cover: Math.round(data.current.cloud_cover),
          wind_speed: Math.round(data.current.wind_speed_10m),
          condition: getCondition(data.current.cloud_cover, data.current.rain)
        },
        hourly: data.hourly.time.slice(0, 8).map((time, i) => ({
          time: new Date(time).getHours() + ':00',
          temp: Math.round(data.hourly.temperature_2m[i]),
          precip: data.hourly.precipitation_probability[i] || 0,
          icon: getWeatherIcon(data.hourly.cloud_cover[i], data.hourly.precipitation[i])
        })),
        daily: data.daily.time.slice(0, 7).map((time, i) => ({
          day: getDayName(time, i),
          high: Math.round(data.daily.temperature_2m_max[i]),
          low: Math.round(data.daily.temperature_2m_min[i]),
          precip: data.daily.precipitation_sum[i] || 0
        }))
      });
    } catch (error) {
      console.error('Weather fetch error:', error);
    }
    setWeatherLoading(false);
  };

  const getCondition = (cloud, rain) => {
    if (rain > 0) return 'Rainy';
    if (cloud > 75) return 'Cloudy';
    if (cloud > 40) return 'Partly Cloudy';
    return 'Clear';
  };

  const getWeatherIcon = (cloud, rain) => {
    if (rain > 0) return '🌧️';
    if (cloud > 75) return '☁️';
    if (cloud > 40) return '⛅';
    return '☀️';
  };

  const getDayName = (dateStr, index) => {
    if (index === 0) return 'Today';
    if (index === 1) return 'Tomorrow';
    return new Date(dateStr).toLocaleDateString('en-US', { weekday: 'short' });
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setFormLoading(true);

    try {
      const response = await fetch(`${API_BASE}/login.php`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password })
      });

      const data = await response.json();

      if (data.success) {
        setUser(data.user);
        localStorage.setItem('auth_token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        setPage('dashboard');
      } else {
        setError(data.error || 'Login failed');
      }
    } catch (err) {
      setError('Connection error. Make sure XAMPP Apache is running.');
    } finally {
      setFormLoading(false);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setError('');
    setFormLoading(true);

    try {
      const response = await fetch(`${API_BASE}/register.php`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password, name, phone, parish: 'saint-george' })
      });

      const data = await response.json();

      if (data.success) {
        setUser(data.user);
        localStorage.setItem('auth_token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        setPage('dashboard');
      } else {
        setError(data.error || 'Registration failed');
      }
    } catch (err) {
      setError('Connection error.');
    } finally {
      setFormLoading(false);
    }
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('auth_token');
    localStorage.removeItem('user');
    setPage('login');
    setWeather(null);
  };

  if (loading) {
    return (
      <div className="loading-screen">
        <div className="spinner"></div>
        <p>Loading WeatherAlert...</p>
      </div>
    );
  }

  // Login Page
  if (page === 'login' && !user) {
    return (
      <div className="auth-container">
        <div className="auth-card">
          <div className="auth-header">
            <div className="logo">🌅</div>
            <h1>WeatherAlert</h1>
            <p>Grenada Weather Monitoring System</p>
          </div>

          <form onSubmit={handleLogin} className="auth-form">
            <h2>Sign In</h2>

            {error && <div className="error-message">{error}</div>}

            <div className="form-group">
              <label>Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="your.email@example.com"
                required
              />
            </div>

            <div className="form-group">
              <label>Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Enter your password"
                required
              />
            </div>

            <button type="submit" className="btn-primary" disabled={formLoading}>
              {formLoading ? 'Signing in...' : 'Sign In'}
            </button>

            <p className="auth-link">
              Don't have an account? <a href="#" onClick={() => setPage('register')}>Register here</a>
            </p>

            <div className="admin-hint">
              <small>Admin: shenait0323@gmail.com / WeatherAdmin2024!</small>
            </div>
          </form>
        </div>
      </div>
    );
  }

  // Register Page
  if (page === 'register' && !user) {
    return (
      <div className="auth-container">
        <div className="auth-card">
          <div className="auth-header">
            <div className="logo">🌅</div>
            <h1>WeatherAlert</h1>
            <p>Grenada Weather Monitoring System</p>
          </div>

          <form onSubmit={handleRegister} className="auth-form">
            <h2>Create Account</h2>

            {error && <div className="error-message">{error}</div>}

            <div className="form-group">
              <label>Full Name</label>
              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="John Doe"
                required
              />
            </div>

            <div className="form-group">
              <label>Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="your.email@example.com"
                required
              />
            </div>

            <div className="form-group">
              <label>Phone (optional)</label>
              <input
                type="tel"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                placeholder="+1 473 XXX XXXX"
              />
            </div>

            <div className="form-group">
              <label>Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Choose a password"
                required
              />
            </div>

            <button type="submit" className="btn-primary" disabled={formLoading}>
              {formLoading ? 'Creating account...' : 'Register'}
            </button>

            <p className="auth-link">
              Already have an account? <a href="#" onClick={() => setPage('login')}>Sign in here</a>
            </p>
          </form>
        </div>
      </div>
    );
  }

  // Dashboard with Weather
  return (
    <div className="dashboard" style={{background: isDark ? '#0f1117' : '#e3f2fd', minHeight: '100vh'}}>
      <nav className="navbar">
        <div className="navbar-brand">
          <span className="logo">🌅</span>
          <span>WeatherAlert</span>
        </div>
        <div className="navbar-menu">
          <select 
            value={parish.id} 
            onChange={(e) => setParish(PARISHES.find(p => p.id === e.target.value))}
            style={{padding: '8px 12px', borderRadius: '8px', border: '1px solid #ddd', marginRight: '15px'}}
          >
            {PARISHES.map(p => (
              <option key={p.id} value={p.id}>{p.name}</option>
            ))}
          </select>
          <span style={{color: '#666', marginRight: '15px'}}>Welcome, {user.name}!</span>
          {user.role === 'admin' && <span style={{background: '#667eea', color: 'white', padding: '4px 12px', borderRadius: '6px', fontSize: '12px', marginRight: '10px'}}>ADMIN</span>}
          <button onClick={() => setIsDark(!isDark)} style={{padding: '8px 12px', borderRadius: '8px', border: 'none', background: '#f0f0f0', marginRight: '10px', cursor: 'pointer'}}>{isDark ? '☀️' : '🌙'}</button>
          <button onClick={handleLogout} className="btn-logout">Logout</button>
        </div>
      </nav>

      <div className="container">
        {weatherLoading ? (
          <div style={{textAlign: 'center', padding: '60px'}}>
            <div className="spinner"></div>
            <p>Loading weather data...</p>
          </div>
        ) : weather ? (
          <>
            {/* Current Weather */}
            <div className="weather-card">
              <div className="location">{parish.capital}, {parish.name}</div>
              <div className="temp">{weather.current.temperature}°</div>
              <div className="condition">{weather.current.condition}</div>
              <div className="stat-grid">
                <div className="stat-item">
                  <div className="stat-label">Humidity</div>
                  <div className="stat-value">{weather.current.humidity}%</div>
                </div>
                <div className="stat-item">
                  <div className="stat-label">Wind</div>
                  <div className="stat-value">{weather.current.wind_speed} km/h</div>
                </div>
                <div className="stat-item">
                  <div className="stat-label">Cloud Cover</div>
                  <div className="stat-value">{weather.current.cloud_cover}%</div>
                </div>
                <div className="stat-item">
                  <div className="stat-label">Rain</div>
                  <div className="stat-value">{weather.current.rain} mm</div>
                </div>
              </div>
            </div>

            {/* Hourly Forecast */}
            <div className="card">
              <h2>Hourly Forecast</h2>
              <div style={{display: 'flex', gap: '15px', overflowX: 'auto', padding: '10px 0'}}>
                {weather.hourly.map((h, i) => (
                  <div key={i} style={{textAlign: 'center', minWidth: '80px', padding: '15px', background: '#f8f9fa', borderRadius: '12px'}}>
                    <div style={{fontSize: '14px', color: '#666', marginBottom: '8px'}}>{h.time}</div>
                    <div style={{fontSize: '32px', marginBottom: '8px'}}>{h.icon}</div>
                    <div style={{fontSize: '18px', fontWeight: '600', marginBottom: '5px'}}>{h.temp}°</div>
                    <div style={{fontSize: '12px', color: '#999'}}>💧 {h.precip}%</div>
                  </div>
                ))}
              </div>
            </div>

            {/* 7-Day Forecast */}
            <div className="card">
              <h2>7-Day Forecast</h2>
              {weather.daily.map((d, i) => (
                <div key={i} style={{display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '12px 0', borderBottom: i < weather.daily.length - 1 ? '1px solid #eee' : 'none'}}>
                  <div style={{width: '100px', fontWeight: i === 0 ? '600' : '400'}}>{d.day}</div>
                  <div style={{flex: 1, textAlign: 'center'}}>☀️</div>
                  <div style={{display: 'flex', gap: '20px', width: '120px', justifyContent: 'flex-end'}}>
                    <span style={{fontWeight: '600'}}>{d.high}°</span>
                    <span style={{color: '#999'}}>{d.low}°</span>
                  </div>
                </div>
              ))}
            </div>
          </>
        ) : (
          <div className="card">
            <p>Click refresh to load weather data</p>
            <button onClick={fetchWeather} style={{marginTop: '10px', padding: '10px 20px', borderRadius: '8px', border: 'none', background: '#667eea', color: 'white', cursor: 'pointer'}}>
              Load Weather
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
